using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;

public class ReportController : Controller
{
    private readonly ILogger<ReportController> _logger;

    public ReportController(ILogger<ReportController> logger)
    {
        _logger = logger;
    }

    // Was: btnExport_Click with Response.Write + Response.End()
    // Response.End() called Thread.Abort internally — not available in .NET 8.
    // In ASP.NET Core, just return an IActionResult. The framework handles the response lifecycle.
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv");
    }

    // Was: btnRedirect_Click with Response.Redirect(url, true) + catch(ThreadAbortException)
    // Response.Redirect(url, true) called Thread.Abort to stop execution after the redirect.
    // In ASP.NET Core, return RedirectResult — execution naturally stops after return.
    [HttpPost]
    public IActionResult ProcessAndRedirect()
    {
        if (!User.Identity?.IsAuthenticated ?? true)
        {
            return Redirect("/login");
        }

        try
        {
            ProcessRequest();
            return Redirect("/success");
        }
        // ThreadAbortException catch block REMOVED:
        // - It existed only because Response.Redirect(url, true) threw it as a side-effect.
        // - In ASP.NET Core, Redirect() returns a result object — no exception is thrown.
        // - Catching OperationCanceledException here is also unnecessary since we're not
        //   doing any cancellable async work.
        catch (Exception ex)
        {
            LogError(ex);
            return Redirect("/error");
        }
    }

    private string GenerateReport() => "Id,Name\n1,Example";
    private void ProcessRequest() { /* business logic */ }
    private void LogError(Exception ex) => _logger.LogError(ex, "Request processing failed");
}

